mapper.select:
SELECT id, name, account, password, status
FROM sys_user
WHERE id = #{id}

mapper.update:
UPDATE sys_user
SET name = #{name},
    account = #{account},
    password = #{password},
    status = #{status}
WHERE id = #{id}

mapper.select:
SELECT id, name, account, password, status FROM sys_user
name LIKE CONCAT('%', #{name}, '%')
LIMIT #{start}, #{size}
